var doc = Rhino.RhinoDoc.ActiveDoc;
var xform = Rhino.Geometry.Transform.Rotation(Math.PI / 4, Rhino.Geometry.Vector3d.ZAxis, Rhino.Geometry.Point3d.Origin);
int rotated = 0;
foreach (var obj in doc.Objects.GetSelectedObjects(false, false))
{
    if (doc.Objects.Transform(obj.Id, xform, true) != Guid.Empty) rotated++;
}
doc.Views.Redraw();
return new { rotated = rotated, degrees = 45, axis = "Z" };
